argument.script:
async (intermediate) => {
  const ctx = window.__ICE_APP_CONTEXT__;
  if (!ctx) return [{ error: "__ICE_APP_CONTEXT__ not found" }];
  const d = ctx.loaderData?.home?.data?.res;
  if (!d) return [{ error: "res data not found" }];
  const item = d.item || {};
  const seller = d.seller || {};
  const skuCore = d.skuCore || {};
  const skuBase = d.skuBase || {};
  const comp = d.componentsVO || {};
  const titleVO = comp.titleVO || {};
  const storeCardVO = comp.storeCardVO || {};
  const deliveryVO = comp.deliveryVO || {};
  const rateVO = comp.rateVO || {};
  const priceVO = comp.priceVO || {};
  const sku2info = skuCore.sku2info || {};
  const skuList = skuBase.skus || [];
  const sales = item.vagueSellCount || titleVO.salesDesc || "";
  const fallbackCouponPrice = priceVO.extraPrice?.priceText || "";
  const baseInfo = {
    title: item.title || titleVO.title?.title || "",
    itemId: item.itemId || "",
    sales: sales,
    shopName: seller.shopName || storeCardVO.shopName || "",
    shopUrl: seller.pcShopUrl || storeCardVO.shopUrl || "",
    sellerType: seller.sellerType === "B" ? "天猫" : "淘宝",
    creditLevel: seller.creditLevel || storeCardVO.creditLevel || "",
    location: deliveryVO.deliveryFromAddr || "",
    reviewCount: rateVO.totalCount || "",
    favorableRate: rateVO.favorableRate?.rateText || "",
    images: (item.images || comp.headImageVO?.images || []).slice(0, 5)
  };
  const results = [];
  for (const [skuId, skuData] of Object.entries(sku2info)) {
    if (skuId === "0") continue;
    const price = skuData.price || {};
    const subPrice = skuData.subPrice || {};
    let skuName = "";
    const matchSku = skuList.find(s => s.skuId === skuId);
    if (matchSku) {
      skuName = matchSku.propPath || "";
    }
    const couponPrice = subPrice.priceText || fallbackCouponPrice;
    results.push({
      ...baseInfo,
      skuId,
      skuName,
      price: price.priceText || "",
      couponPrice: couponPrice,
      delivery: skuData.logisticsTime || deliveryVO.agingDesc || "",
      quantity: skuData.quantity || 0
    });
  }
  if (results.length === 0) {
    const defaultSku = sku2info["0"] || {};
    const price = defaultSku.price || {};
    const subPrice = defaultSku.subPrice || {};
    const couponPrice = subPrice.priceText || priceVO.extraPrice?.priceText || fallbackCouponPrice;
    results.push({
      ...baseInfo,
      skuId: "0",
      skuName: "默认",
      price: price.priceText || "",
      couponPrice: couponPrice,
      delivery: defaultSku.logisticsTime || deliveryVO.agingDesc || "",
      quantity: defaultSku.quantity || 0
    });
  }
  return results;
}
